class Solution:
 def solve(self, heights: list[int]) -> int:
 n = len(heights)
dp = [0] * (n + 1)
dp[0] = 1
 for i in range(1, n+1):
  for j in range(i):
   if heights[i-1] - heights[j-1] <= j:
    dp[i] += dp[j]
 return dp[-1]

 def main():
  heights = [int(x) for x in input().split(' ')]
  print(Solution().solve(heights))

if __name__== '__main__':
  main()

