#include <iostream>
using namespace std;
class Solution {
 public:
  int solve(vector<int>& heights) {
    int n = heights.size();
    vector<int> dp(n+1);
    dp[0] = 1;
    for (int i = 1; i <= n; i++) {
      for (int j = 0; j < i; j++) {
        if (heights[i-1] - heights[j-1] <= j) 
          dp[i] += dp[j];
      }
    }
    return dp[n];
  }
};
int main() {
  Solution solution;
  int n;
  cin >> n;
  vector<int> heights(n);
  for (int i = 0; i < n; i++)
    cin >> heights[i];
  cout << solution.solve(heights) << endl;
  return 0;
}
